/**
 * PostCSS plugin to strip CSS rules that contain binary/control characters
 * generated by the Tailwind v4 oxide scanner bug.
 * These corrupt characters cause PostCSS "Missed semicolon" parse errors.
 */
const CONTROL_CHAR_RE = /[\x00-\x08\x0e-\x1f\x7f]/;

/** @type {import('postcss').PluginCreator} */
const plugin = () => ({
  postcssPlugin: 'postcss-sanitize-binary',
  Once(root) {
    root.walk((node) => {
      // Check selectors of rules
      if (node.type === 'rule' && CONTROL_CHAR_RE.test(node.selector)) {
        node.remove();
        return;
      }
      // Check at-rule params
      if (node.type === 'atrule' && CONTROL_CHAR_RE.test(node.params)) {
        node.remove();
        return;
      }
      // Check declaration values
      if (node.type === 'decl') {
        if (CONTROL_CHAR_RE.test(node.prop) || CONTROL_CHAR_RE.test(node.value)) {
          node.remove();
          return;
        }
      }
    });
  },
});

plugin.postcss = true;
export default plugin;
